{
  "mode": "method",
  "tests": [
    {
      "name": "basic_infusion_test",
      "input": {
        "track": "sample_track_1.mp3",
        "gamma_intensity": 10,
        "theta_intensity": 15
      },
      "output": {
        "inclusion_percentage": 25,
        "listenability": "pass"
      },
      "notes": "Tests basic infusion of gamma and theta frequencies into a standard track."
    },
    {
      "name": "high_intensity_infusion_test",
      "input": {
        "track": "sample_track_2.mp3",
        "gamma_intensity": 50,
        "theta_intensity": 50
      },
      "output": {
        "inclusion_percentage": 100,
        "listenability": "fail"
      },
      "notes": "Tests high intensity infusion where listenability is expected to fail."
    },
    {
      "name": "low_intensity_infusion_test",
      "input": {
        "track": "sample_track_3.mp3",
        "gamma_intensity": 5,
        "theta_intensity": 5
      },
      "output": {
        "inclusion_percentage": 10,
        "listenability": "pass"
      },
      "notes": "Tests low intensity infusion to ensure minimal impact on listenability."
    },
    {
      "name": "edge_case_silent_track",
      "input": {
        "track": "silent_track.mp3",
        "gamma_intensity": 10,
        "theta_intensity": 10
      },
      "output": {
        "inclusion_percentage": 0,
        "listenability": "pass"
      },
      "notes": "Tests the algorithm's behavior with a silent track."
    },
    {
      "name": "edge_case_distorted_track",
      "input": {
        "track": "distorted_track.mp3",
        "gamma_intensity": 20,
        "theta_intensity": 20
      },
      "output": {
        "inclusion_percentage": 30,
        "listenability": "fail"
      },
      "notes": "Tests how the algorithm handles a distorted track."
    },
    {
      "name": "high_quality_track_test",
      "input": {
        "track": "high_quality_track.mp3",
        "gamma_intensity": 15,
        "theta_intensity": 20
      },
      "output": {
        "inclusion_percentage": 35,
        "listenability": "pass"
      },
      "notes": "Tests infusion on a high-quality track to ensure listenability is maintained."
    },
    {
      "name": "mixed_genre_track_test",
      "input": {
        "track": "mixed_genre_track.mp3",
        "gamma_intensity": 25,
        "theta_intensity": 30
      },
      "output": {
        "inclusion_percentage": 55,
        "listenability": "pass"
      },
      "notes": "Tests infusion on a track with mixed genres to evaluate adaptability."
    },
    {
      "name": "maximum_intensity_test",
      "input": {
        "track": "sample_track_4.mp3",
        "gamma_intensity": 100,
        "theta_intensity": 100
      },
      "output": {
        "inclusion_percentage": 100,
        "listenability": "fail"
      },
      "notes": "Tests the upper limit of intensity to ensure listenability is compromised."
    }
  ],
  "assumptions": "Tracks are in MP3 format and the algorithm can handle various audio qualities.",
  "notes": "Ensure to validate the listenability through human testing."
}
